const MAX_PX=1800, TARGET_KB=400, MIN_QUALITY=0.45;
function compressImage(file) {
  return new Promise(resolve => {
    const reader=new FileReader();
    reader.onload=e=>{
      const img=new Image();
      img.onload=()=>{
        let {naturalWidth:w,naturalHeight:h}=img;
        const origW=w,origH=h;
        if(w>MAX_PX||h>MAX_PX){const r=Math.min(MAX_PX/w,MAX_PX/h);w=Math.round(w*r);h=Math.round(h*r);}
        const canvas=document.createElement("canvas");
        canvas.width=w;canvas.height=h;
        canvas.getContext("2d").drawImage(img,0,0,w,h);
        let lo=MIN_QUALITY,hi=0.92,best="";
        for(let i=0;i<8;i++){const mid=(lo+hi)/2;const d=canvas.toDataURL("image/jpeg",mid);const kb=Math.round(d.length*3/4/1024);best=d;if(kb>TARGET_KB)hi=mid;else{lo=mid;best=d;}if(hi-lo<0.02)break;}
        if(Math.round(best.length*3/4/1024)>TARGET_KB)best=canvas.toDataURL("image/jpeg",MIN_QUALITY);
        resolve({dataUrl:best,origW,origH,newW:w,newH:h,kb:Math.round(best.length*3/4/1024)});
      };
      img.src=e.target.result;
    };
    reader.readAsDataURL(file);
  });
}

const sbHeaders={"apikey":SB_KEY,"Authorization":`Bearer ${SB_KEY}`,"Content-Type":"application/json","Prefer":"return=representation"};
async function sbQuery(table,queryString=""){
  let all=[],from=0;
  const batchSize=1000;
  while(true){
    const url=`${SB_URL}/rest/v1/${table}?${queryString}`;
    const res=await fetch(url,{headers:{...sbHeaders,"Range":`${from}-${from+batchSize-1}`,"Range-Unit":"items"}});
    if(!res.ok)throw new Error(await res.text());
    const batch=await res.json();
    if(!Array.isArray(batch)||batch.length===0)break;
    all=[...all,...batch];
    if(batch.length<batchSize)break;
    from+=batchSize;
  }
  return all;
}
async function sbInsert(table,data){
  // Strip undefined values so missing columns don't cause schema errors
  const clean=Object.fromEntries(Object.entries(data).filter(([,v])=>v!==undefined));
  const res=await fetch(`${SB_URL}/rest/v1/${table}`,{method:"POST",headers:sbHeaders,body:JSON.stringify(clean)});
  if(!res.ok) throw new Error(await res.text());
  return res.json();
}
async function sbDelete(table,id){const res=await fetch(`${SB_URL}/rest/v1/${table}?id=eq.${id}`,{method:"DELETE",headers:sbHeaders});if(!res.ok)throw new Error(await res.text());}
async function sbUpdate(table,id,data){
  const clean=Object.fromEntries(Object.entries(data).filter(([,v])=>v!==undefined));
  const res=await fetch(`${SB_URL}/rest/v1/${table}?id=eq.${id}`,{method:"PATCH",headers:{...sbHeaders,"Prefer":"return=representation"},body:JSON.stringify(clean)});
  if(!res.ok) throw new Error(await res.text());
  return res.json();
}
async function sbUploadImage(bucket,dataUrl){
  const res=await fetch(dataUrl);
  const blob=await res.blob();
  const path=`${Date.now()}-${Math.random().toString(36).slice(2)}.jpg`;
  const up=await fetch(`${SB_URL}/storage/v1/object/${bucket}/${path}`,{
    method:"POST",
    headers:{"apikey":SB_KEY,"Authorization":`Bearer ${SB_KEY}`,"Content-Type":"image/jpeg","x-upsert":"true"},
    body:blob
  });
  if(!up.ok){
    const errText=await up.text();
    throw new Error(`Storage upload failed: ${errText}`);
  }
  return `${SB_URL}/storage/v1/object/public/${bucket}/${path}`;
}

function Btn({onClick,children}){const [h,setH]=useState(false);return <button type="button" onClick={onClick} onMouseOver={()=>setH(true)} onMouseOut={()=>setH(false)} style={{background:h?C.orange:C.black,color:C.white,border:"none",cursor:"pointer",padding:"10px 20px",fontSize:10,letterSpacing:"0.12em",textTransform:"uppercase",fontFamily:"DM Sans,sans-serif",transition:"background 0.2s"}}>{children}</button>;}
function DangerBtn({onClick,children}){return <button onClick={onClick} style={{background:"none",border:"none",cursor:"pointer",color:"#cc3333",fontSize:11,letterSpacing:"0.08em",textTransform:"uppercase",fontFamily:"DM Sans,sans-serif"}}>{children}</button>;}
function FInput({label,value,onChange,placeholder}){return <div style={{marginBottom:20}}><label style={{fontSize:10,letterSpacing:"0.18em",textTransform:"uppercase",color:C.grey,display:"block",marginBottom:8}}>{label}</label><input value={value} onChange={onChange} placeholder={placeholder} style={{width:"100%",padding:"10px 14px",border:`1px solid ${C.border}`,background:C.white,fontFamily:"DM Sans,sans-serif",fontSize:13,outline:"none",color:C.black,boxSizing:"border-box"}}/></div>;}
function FTextarea({label,value,onChange,placeholder}){return <div style={{marginBottom:20}}><label style={{fontSize:10,letterSpacing:"0.18em",textTransform:"uppercase",color:C.grey,display:"block",marginBottom:8}}>{label}</label><textarea value={value} onChange={onChange} placeholder={placeholder} rows={4} style={{width:"100%",padding:"10px 14px",border:`1px solid ${C.border}`,background:C.white,fontFamily:"DM Sans,sans-serif",fontSize:13,outline:"none",color:C.black,resize:"vertical",lineHeight:1.6,boxSizing:"border-box"}}/></div>;}
function FSelect({label,value,onChange,options}){return <div style={{marginBottom:20}}><label style={{fontSize:10,letterSpacing:"0.18em",textTransform:"uppercase",color:C.grey,display:"block",marginBottom:8}}>{label}</label><select value={value} onChange={onChange} style={{width:"100%",padding:"10px 14px",border:`1px solid ${C.border}`,background:C.white,fontFamily:"DM Sans,sans-serif",fontSize:13,outline:"none",appearance:"none",color:C.black,boxSizing:"border-box"}}>{options.map(o=><option key={o.value||o} value={o.value||o}>{o.label||o}</option>)}</select></div>;}
function SuccessMsg({show,text}){if(!show)return null;return <div style={{padding:"12px 16px",background:"#f0fff4",border:"1px solid #a3e9b5",fontSize:12,color:"#1a7a3c",marginBottom:20}}>{text}</div>;}
function ErrMsg({text}){if(!text)return null;return <div style={{padding:"12px 16px",background:"#fff0f0",border:"1px solid #ffcccc",fontSize:12,color:"#cc0000",marginBottom:20}}>{text}</div>;}

