function Modal({title,onClose,children}){
  return(
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.5)",zIndex:1000,display:"flex",alignItems:"flex-start",justifyContent:"center",overflowY:"auto",padding:"40px 20px"}}>
      <div style={{background:C.white,width:"100%",maxWidth:900,position:"relative",boxShadow:"0 20px 60px rgba(0,0,0,0.15)"}}>
        <div style={{padding:"20px 28px",borderBottom:`1px solid ${C.border}`,display:"flex",alignItems:"center",justifyContent:"space-between"}}>
          <div style={{fontFamily:"Cormorant Garamond,serif",fontSize:24,fontWeight:400}}>{title}</div>
          <button onClick={onClose} style={{background:"none",border:"none",cursor:"pointer",fontSize:24,color:C.lightGrey,lineHeight:1}}>×</button>
        </div>
        <div style={{padding:28}}>{children}</div>
      </div>
    </div>
  );
}

function ArtistsList({artists,artworks,reload,onViewWorks}){
  const [busy,setBusy]=useState("");
  const [editing,setEditing]=useState(null); // artist object being edited
  const [saving,setSaving]=useState(false);
  const [err,setErr]=useState("");

  const del=async id=>{
    if(!confirm("Delete this artist and all their artworks?"))return;
    setBusy(id);
    try{await sbDelete("artists",id);await reload();}
    catch(e){alert("Error: "+e.message);}
    setBusy("");
  };

  const openEdit=a=>setEditing({...a});
  const f=k=>e=>setEditing(p=>({...p,[k]:e.target.value}));

  const saveEdit=async()=>{
    if(!editing.name.trim()){setErr("Name required.");return;}
    setSaving(true);setErr("");
    try{
      const {id,_portraitData,...rest}=editing;
      let portrait_url=editing.portrait_url||"";
      if(_portraitData) portrait_url=await sbUploadImage("artist-portraits",_portraitData);
      await sbUpdate("artists",id,{
        name:        editing.name.trim(),
        nationality: editing.nationality||null,
        medium:      editing.medium||null,
        bio:         editing.bio||null,
        link:        editing.link||null,
        portrait_url,
      });
      await reload();
      setEditing(null);
    }catch(e){setErr("Error: "+e.message);}
    setSaving(false);
  };

  const handlePortrait=async e=>{
    const file=e.target.files[0];if(!file)return;
    const {dataUrl}=await compressImage(file);
    setEditing(p=>({...p,_portraitData:dataUrl}));
  };

  return(<>
    {!artists.length&&<div style={{padding:24,color:C.grey,fontSize:12}}>No artists yet.</div>}
    <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:1,background:C.border}}>
      {[...artists].sort((a,b)=>a.name.localeCompare(b.name)).map(a=>{
        const count=artworks.filter(w=>w.artist_id===a.id).length;
        return(
          <div key={a.id} style={{background:C.white,padding:"10px 14px",display:"flex",alignItems:"center",justifyContent:"space-between",gap:8}}>
            <div style={{minWidth:0}}>
              <div style={{fontFamily:"Cormorant Garamond,serif",fontSize:15,fontWeight:400,color:C.black,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{a.name}</div>
              <div style={{fontSize:10,color:C.lightGrey,marginTop:2,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>
                  {a.medium} · <span onClick={e=>{e.stopPropagation();onViewWorks(a.id);}} style={{color:C.orange,cursor:"pointer",textDecoration:"underline"}}>{count} work{count!==1?"s":""}</span>
                </div>
            </div>
            <div style={{display:"flex",gap:10,flexShrink:0}}>
              <button onClick={()=>openEdit(a)} style={{background:"none",border:"none",cursor:"pointer",fontSize:10,letterSpacing:"0.08em",textTransform:"uppercase",fontFamily:"DM Sans,sans-serif",color:C.orange,whiteSpace:"nowrap"}}>Edit</button>
              {busy===a.id?<span style={{fontSize:10,color:C.grey}}>…</span>:<DangerBtn onClick={()=>del(a.id)}>Delete</DangerBtn>}
            </div>
          </div>
        );
      })}
    </div>

    {/* Edit Artist Modal */}
    {editing&&(
      <Modal title={`Edit — ${editing.name}`} onClose={()=>setEditing(null)}>
        <ErrMsg text={err}/>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:24}}>
          <div>
            <FInput label="Full Name *" value={editing.name||""} onChange={f("name")} placeholder="Artist name"/>
            <FInput label="Nationality / Origin" value={editing.nationality||""} onChange={f("nationality")} placeholder="e.g. Nigerian, b. 1980"/>
            <FInput label="Primary Medium" value={editing.medium||""} onChange={f("medium")} placeholder="e.g. Oil on canvas"/>
            <FTextarea label="Biography" value={editing.bio||""} onChange={f("bio")} placeholder="2–4 sentences…"/>
            <FInput label="Website / Instagram" value={editing.link||""} onChange={f("link")} placeholder="https://…"/>
          </div>
          <div>
            <label style={{fontSize:10,letterSpacing:"0.18em",textTransform:"uppercase",color:C.grey,display:"block",marginBottom:8}}>Portrait</label>
            <div style={{border:`1.5px dashed ${C.border}`,padding:20,textAlign:"center",position:"relative",cursor:"pointer",marginBottom:16}}>
              <input type="file" accept="image/*" onChange={handlePortrait} style={{position:"absolute",inset:0,opacity:0,cursor:"pointer",width:"100%",height:"100%"}}/>
              {(editing._portraitData||editing.portrait_url)
                ?<img src={editing._portraitData||editing.portrait_url} alt="" style={{maxWidth:"100%",maxHeight:140,objectFit:"contain"}}/>
                :<div style={{fontSize:12,color:C.grey}}>Upload new portrait</div>}
            </div>
          </div>
        </div>
        <div style={{display:"flex",gap:12,marginTop:8}}>
          <Btn onClick={saveEdit}>{saving?"Saving…":"Save Changes"}</Btn>
          <button onClick={()=>setEditing(null)} style={{background:"none",border:`1px solid ${C.border}`,cursor:"pointer",padding:"10px 20px",fontSize:10,letterSpacing:"0.12em",textTransform:"uppercase",fontFamily:"DM Sans,sans-serif",color:C.grey}}>Cancel</button>
        </div>
      </Modal>
    )}
  </>);
}

function ArtworksList({artists,artworks,reload,initFilterArtistId}){
  const [busy,setBusy]=useState("");
  const [editing,setEditing]=useState(null);
  const [saving,setSaving]=useState(false);
  const [err,setErr]=useState("");
  const [selected,setSelected]=useState(new Set());
  const [batchDeleting,setBatchDeleting]=useState(false);
  const [filterArtist,setFilterArtist]=useState(initFilterArtistId||"");
  const [sortBy,setSortBy]=useState("recent");

  const toggleSelect=id=>setSelected(prev=>{const s=new Set(prev);s.has(id)?s.delete(id):s.add(id);return s;});
  const selectAll=()=>setSelected(new Set(artworks.map(w=>w.id)));
  const clearSelect=()=>setSelected(new Set());

  const batchDelete=async()=>{
    if(!selected.size) return;
    if(!confirm(`Delete ${selected.size} selected artwork${selected.size!==1?"s":""}? This cannot be undone.`)) return;
    setBatchDeleting(true);
    for(const id of selected){
      try{await sbDelete("artworks",id);}catch(e){}
    }
    setSelected(new Set());
    await reload();
    setBatchDeleting(false);
  };

  const del=async id=>{
    if(!confirm("Delete this artwork?"))return;
    setBusy(id);
    try{await sbDelete("artworks",id);await reload();}
    catch(e){alert("Error: "+e.message);}
    setBusy("");
  };

  const openEdit=w=>setEditing({...w,tags:w.tags||[]});
  const f=k=>e=>setEditing(p=>({...p,[k]:e.target.value}));

  const handleNewImage=async e=>{
    const file=e.target.files[0];if(!file)return;
    const {dataUrl,origW,origH}=await compressImage(file);
    setEditing(p=>({...p,_newImageData:dataUrl,dimensions:p.dimensions||`${origW} × ${origH} px`}));
  };

  const saveEdit=async()=>{
    if(!editing.title.trim()){setErr("Title required.");return;}
    setSaving(true);setErr("");
    try{
      const {id,_newImageData,...rest}=editing;
      let image_url=editing.image_url;
      if(_newImageData) image_url=await sbUploadImage("artwork-images",_newImageData);
      await sbUpdate("artworks",id,{
        artist_id:     editing.artist_id,
        title:         editing.title.trim(),
        year:          editing.year||null,
        medium:        editing.medium||null,
        dimensions:    editing.dimensions||null,
        series:        editing.series||null,
        availability:  editing.availability,
        writeup:       editing.writeup||null,
        price:         editing.price||null,
        tags:          editing.tags||[],
        image_position:editing.image_position||"center",
        image_url,
      });
      await reload();
      setEditing(null);
    }catch(e){setErr("Error: "+e.message);}
    setSaving(false);
  };

  return(<>
    {/* Filter + Sort bar */}
    <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:16,flexWrap:"wrap"}}>
      <select value={filterArtist} onChange={e=>{setFilterArtist(e.target.value);setSelected(new Set());}}
        style={{padding:"8px 14px",border:`1px solid ${C.border}`,fontFamily:"DM Sans,sans-serif",fontSize:12,outline:"none",appearance:"none",background:C.white,color:C.black,minWidth:200}}>
        <option value="">All Artists</option>
        {[...artists].sort((a,b)=>a.name.localeCompare(b.name)).map(a=><option key={a.id} value={a.id}>{a.name}</option>)}
      </select>
      <div style={{display:"flex",gap:0,border:`1px solid ${C.border}`}}>
        {[{v:"recent",l:"Most Recent"},{v:"artist",l:"By Artist"}].map(s=>(
          <button key={s.v} onClick={()=>setSortBy(s.v)}
            style={{background:sortBy===s.v?C.black:C.white,color:sortBy===s.v?C.white:C.grey,border:"none",cursor:"pointer",padding:"8px 14px",fontSize:10,letterSpacing:"0.1em",textTransform:"uppercase",fontFamily:"DM Sans,sans-serif",transition:"all 0.15s"}}>
            {s.l}
          </button>
        ))}
      </div>
      {filterArtist&&<button onClick={()=>setFilterArtist("")} style={{background:"none",border:"none",cursor:"pointer",fontSize:10,color:C.grey,fontFamily:"DM Sans,sans-serif",letterSpacing:"0.1em",textTransform:"uppercase"}}>Clear filter ×</button>}
    </div>

    {/* Batch controls */}
    <div style={{display:"flex",alignItems:"center",gap:16,marginBottom:12,padding:"10px 0"}}>
      <button onClick={selectAll} style={{background:"none",border:"none",cursor:"pointer",fontSize:10,letterSpacing:"0.1em",textTransform:"uppercase",fontFamily:"DM Sans,sans-serif",color:C.grey}}>Select All</button>
      <button onClick={clearSelect} style={{background:"none",border:"none",cursor:"pointer",fontSize:10,letterSpacing:"0.1em",textTransform:"uppercase",fontFamily:"DM Sans,sans-serif",color:C.grey}}>Clear</button>
      {selected.size>0&&(
        <button onClick={batchDelete}
          style={{background:batchDeleting?"#cc3333":"#cc3333",color:C.white,border:"none",cursor:"pointer",padding:"7px 16px",fontSize:10,letterSpacing:"0.1em",textTransform:"uppercase",fontFamily:"DM Sans,sans-serif"}}>
          {batchDeleting?`Deleting…`:`Delete ${selected.size} Selected`}
        </button>
      )}
      {selected.size>0&&<span style={{fontSize:11,color:C.grey}}>{selected.size} selected</span>}
    </div>

    <table style={{width:"100%",borderCollapse:"collapse"}}>
      <thead><tr>{["","","Title","Artist","Year","Medium",""].map((h,i)=><th key={i} style={{fontSize:10,letterSpacing:"0.15em",textTransform:"uppercase",color:C.grey,padding:"10px 12px",borderBottom:`1px solid ${C.border}`,textAlign:"left"}}>{h}</th>)}</tr></thead>
      <tbody>
        {(()=>{
          let display=[...artworks];
          if(filterArtist) display=display.filter(w=>w.artist_id===filterArtist);
          if(sortBy==="artist") display.sort((a,b)=>{const na=artists.find(x=>x.id===a.artist_id)?.name||"";const nb=artists.find(x=>x.id===b.artist_id)?.name||"";return na.localeCompare(nb);});
          else display.sort((a,b)=>new Date(b.created_at||0)-new Date(a.created_at||0));
          if(!display.length) return <tr><td colSpan={7} style={{padding:24,color:C.grey}}>{filterArtist?"No artworks for this artist.":"No artworks yet."}</td></tr>;
          return display.map(w=>{
          const art=artists.find(a=>a.id===w.artist_id);
          const isSel=selected.has(w.id);
          return<tr key={w.id} style={{background:isSel?"#fff8f5":"transparent"}}>
            <td style={{padding:"10px 12px",borderBottom:`1px solid ${C.border}`}}>
              <input type="checkbox" checked={isSel} onChange={()=>toggleSelect(w.id)}
                style={{width:14,height:14,cursor:"pointer",accentColor:C.orange}}/>
            </td>
            <td style={{padding:"10px 12px",borderBottom:`1px solid ${C.border}`}}><img src={w.image_url} alt="" style={{width:40,height:40,objectFit:"cover",background:C.border,display:"block"}}/></td>
            <td style={{padding:"10px 12px",borderBottom:`1px solid ${C.border}`,fontFamily:"Cormorant Garamond,serif",fontSize:17}}>{w.title}</td>
            <td style={{padding:"10px 12px",borderBottom:`1px solid ${C.border}`,fontSize:13,color:C.charcoal}}>{art?.name}</td>
            <td style={{padding:"10px 12px",borderBottom:`1px solid ${C.border}`,fontSize:13}}>{w.year}</td>
            <td style={{padding:"10px 12px",borderBottom:`1px solid ${C.border}`,fontSize:12,color:C.grey}}>{w.medium}</td>
            <td style={{padding:"10px 12px",borderBottom:`1px solid ${C.border}`,display:"flex",gap:12,alignItems:"center"}}>
              <button onClick={()=>openEdit(w)} style={{background:"none",border:"none",cursor:"pointer",fontSize:11,letterSpacing:"0.08em",textTransform:"uppercase",fontFamily:"DM Sans,sans-serif",color:C.orange}}>Edit</button>
              {busy===w.id?<span style={{fontSize:11,color:C.grey}}>Deleting…</span>:<DangerBtn onClick={()=>del(w.id)}>Delete</DangerBtn>}
            </td>
          </tr>;
        });})()}
      </tbody>
    </table>

    {/* Edit Artwork Modal */}
    {editing&&(
      <Modal title={`Edit — ${editing.title}`} onClose={()=>setEditing(null)}>
        <ErrMsg text={err}/>
        <div style={{display:"grid",gridTemplateColumns:"200px 1fr 1fr",gap:24}}>
          {/* Image */}
          <div>
            <label style={{fontSize:10,letterSpacing:"0.18em",textTransform:"uppercase",color:C.grey,display:"block",marginBottom:8}}>Image</label>
            <div style={{position:"relative",marginBottom:12}}>
              <img src={editing._newImageData||editing.image_url} alt="" style={{width:"100%",aspectRatio:"1",objectFit:"cover",display:"block",border:`1px solid ${C.border}`}}/>
            </div>
            <div style={{border:`1.5px dashed ${C.border}`,padding:12,textAlign:"center",position:"relative",cursor:"pointer"}}>
              <input type="file" accept="image/*" onChange={handleNewImage} style={{position:"absolute",inset:0,opacity:0,cursor:"pointer",width:"100%",height:"100%"}}/>
              <div style={{fontSize:11,color:C.grey}}>Replace image</div>
            </div>
          </div>
          {/* Left fields */}
          <div>
            <FInput label="Title *" value={editing.title||""} onChange={f("title")} placeholder="Artwork title"/>
            <FInput label="Year" value={editing.year||""} onChange={f("year")} placeholder="e.g. 2024"/>
            <FInput label="Medium" value={editing.medium||""} onChange={f("medium")} placeholder="e.g. Oil on canvas"/>
            <FInput label="Dimensions" value={editing.dimensions||""} onChange={f("dimensions")} placeholder="e.g. 24×36"/>
            <FInput label="NGN Price" value={editing.price||""} onChange={f("price")} placeholder="e.g. 4,500,000"/>
          </div>
          {/* Right fields */}
          <div>
            <FSelect label="Artist" value={editing.artist_id||""} onChange={f("artist_id")}
              options={[{value:"",label:"— Select —"},...artists.map(a=>({value:a.id,label:a.name}))]}/>
            <FInput label="Series / Edition" value={editing.series||""} onChange={f("series")} placeholder="e.g. Edition 1/5"/>
            <FSelect label="Availability" value={editing.availability||"Available"} onChange={f("availability")}
              options={["Available","Sold","On Loan","NFS"]}/>
            <FTextarea label="Write-up" value={editing.writeup||""} onChange={f("writeup")} placeholder="Description…"/>
            <PositionToggle value={editing.image_position||"center"} onChange={v=>setEditing(p=>({...p,image_position:v}))}/>
            <TagInput tags={editing.tags||[]} onChange={tags=>setEditing(p=>({...p,tags}))}/>
          </div>
        </div>
        <div style={{display:"flex",gap:12,marginTop:8}}>
          <Btn onClick={saveEdit}>{saving?"Saving…":"Save Changes"}</Btn>
          <button onClick={()=>setEditing(null)} style={{background:"none",border:`1px solid ${C.border}`,cursor:"pointer",padding:"10px 20px",fontSize:10,letterSpacing:"0.12em",textTransform:"uppercase",fontFamily:"DM Sans,sans-serif",color:C.grey}}>Cancel</button>
        </div>
      </Modal>
    )}
  </>);
}

function BatchUpload({artists,reload}){
  const [artistId,setArtistId]=useState("");
  const [sharedMedium,setSharedMedium]=useState("");
  const [sharedYear,setSharedYear]=useState("");
  const [items,setItems]=useState([]);
  const [dragging,setDragging]=useState(false);
  const [saving,setSaving]=useState(false);
  const [progress,setProgress]=useState({done:0,total:0});
  const [ok,setOk]=useState(false);
  const [err,setErr]=useState("");

  const parseFile=async file=>{
    const rawName=file.name.replace(/\.[^.]+$/,"");
    const {dataUrl,origW,origH,newW,newH,kb}=await compressImage(file);
    const allParts=rawName.split(",").map(s=>s.trim());
    let parsedArtist="",title="",medium="",dimensions="",year="",price="";
    if(allParts.length>=2){parsedArtist=allParts[0]||"";title=allParts[1]||"";medium=allParts[2]||"";dimensions=allParts[3]||"";year=allParts[4]||"";price=allParts.slice(5).join(",").trim();}
    else{title=rawName.replace(/[-_]/g," ").replace(/\b\w/g,c=>c.toUpperCase());}
    return{id:"b"+Date.now()+Math.random(),image:dataUrl,parsedArtist,title,medium,dimensions,year,price,imageDimensions:`${origW} × ${origH} px`,compressInfo:`${newW}×${newH}px · ${kb}KB`,availability:"Available",writeup:"",tags:[],image_position:"center"};
  };

  const addFiles=async files=>{
    const arr=Array.from(files).filter(f=>f.type.startsWith("image/"));
    const parsed=await Promise.all(arr.map(parseFile));
    const resolved=parsed.map(item=>{
      if(!item.parsedArtist)return item;
      const match=artists.find(a=>a.name.toLowerCase().includes(item.parsedArtist.toLowerCase())||item.parsedArtist.toLowerCase().includes(a.name.toLowerCase()));
      return{...item,resolvedArtistId:match?match.id:"",resolvedArtistName:match?match.name:""};
    });
    setItems(prev=>[...prev,...resolved]);
  };

  const applyShared=()=>setItems(prev=>prev.map(it=>({...it,medium:sharedMedium||it.medium,year:sharedYear||it.year})));
  const update=(id,field,val)=>setItems(prev=>prev.map(it=>it.id===id?{...it,[field]:val}:it));
  const remove=id=>setItems(prev=>prev.filter(it=>it.id!==id));

  const saveAll=async()=>{
    if(!items.length){setErr("No images to save.");return;}
    const unassigned=items.filter(it=>!it.resolvedArtistId&&!artistId);
    if(unassigned.length>0){setErr(`${unassigned.length} artwork(s) have no artist assigned. Use the artist dropdown in each row or set a default artist in Step 1.`);return;}
    setSaving(true);setErr("");setProgress({done:0,total:items.length});
    let failed=0;
    for(let i=0;i<items.length;i++){
      const it=items[i];
      try{
        const image_url=await sbUploadImage("artwork-images",it.image);
        const batchData={
          artist_id:   it.resolvedArtistId||artistId,
          title:       it.title||"Untitled",
          year:        it.year||null,
          medium:      it.medium||null,
          dimensions:  it.dimensions||null,
          availability:it.availability||"Available",
          writeup:     it.writeup||null,
          image_url,
        };
        if(it.price) batchData.price=it.price;
        if(it.tags&&it.tags.length>0) batchData.tags=it.tags;
        if(it.image_position) batchData.image_position=it.image_position;
        await sbInsert("artworks",batchData);
      }catch(e){failed++;}
      setProgress({done:i+1,total:items.length});
    }
    await reload();setSaving(false);
    if(failed>0)setErr(`${failed} artwork(s) failed. The rest were saved.`);
    else{setOk(true);setTimeout(()=>setOk(false),4000);}
    setItems([]);
  };

  return(<div style={{maxWidth:1100}}>
    <SuccessMsg show={ok} text="All artworks saved to Supabase."/>
    <ErrMsg text={err}/>
    <div style={{background:C.white,border:`1px solid ${C.border}`,padding:24,marginBottom:24}}>
      <div style={{fontSize:10,letterSpacing:"0.2em",textTransform:"uppercase",color:C.grey,marginBottom:16}}>Step 1 — Artist &amp; Shared Fields</div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr auto",gap:16,alignItems:"flex-end"}}>
        <FSelect label="Artist *" value={artistId} onChange={e=>setArtistId(e.target.value)} options={[{value:"",label:"— Select artist —"},...artists.map(a=>({value:a.id,label:a.name}))]}/>
        <FInput label="Apply medium to all" value={sharedMedium} onChange={e=>setSharedMedium(e.target.value)} placeholder="e.g. Oil on canvas"/>
        <FInput label="Apply year to all" value={sharedYear} onChange={e=>setSharedYear(e.target.value)} placeholder="e.g. 2024"/>
        <div style={{paddingBottom:20}}><Btn onClick={applyShared}>Apply to All</Btn></div>
      </div>
    </div>
    <div onDrop={async e=>{e.preventDefault();setDragging(false);await addFiles(e.dataTransfer.files);}} onDragOver={e=>{e.preventDefault();setDragging(true);}} onDragLeave={()=>setDragging(false)}
      style={{border:`1.5px dashed ${dragging?C.orange:C.border}`,padding:"40px 24px",textAlign:"center",marginBottom:24,position:"relative",transition:"border-color 0.2s",background:dragging?"#fff8f5":C.white,cursor:"pointer"}}>
      <input type="file" accept="image/*" multiple onChange={e=>addFiles(e.target.files)} style={{position:"absolute",inset:0,opacity:0,cursor:"pointer",width:"100%",height:"100%"}}/>
      <div style={{fontSize:28,color:C.lightGrey,marginBottom:10}}>⊕</div>
      <div style={{fontSize:14,color:C.grey,fontFamily:"Cormorant Garamond,serif",fontWeight:300}}>Drop multiple images here, or click to select</div>
      <div style={{fontSize:10,color:C.lightGrey,marginTop:6,letterSpacing:"0.08em",textTransform:"uppercase"}}>Filename format: Artist, Title, Medium, Dimensions, Year, Price</div>
    </div>
    {saving&&<div style={{marginBottom:24,border:`1px solid ${C.border}`,padding:20,background:C.white}}>
      <div style={{fontSize:11,letterSpacing:"0.12em",textTransform:"uppercase",color:C.grey,marginBottom:12}}>Uploading {progress.done} of {progress.total}…</div>
      <div style={{height:3,background:C.border,borderRadius:2}}><div style={{height:"100%",background:C.orange,borderRadius:2,width:`${progress.total?progress.done/progress.total*100:0}%`,transition:"width 0.3s"}}/></div>
    </div>}
    {items.length>0&&!saving&&(<>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:16}}>
        <div style={{fontSize:10,letterSpacing:"0.2em",textTransform:"uppercase",color:C.grey}}>Step 2 — Review {items.length} Image{items.length!==1?"s":""}</div>
        <div style={{display:"flex",gap:12,alignItems:"center"}}>
          <button onClick={()=>setItems([])} style={{background:"none",border:"none",cursor:"pointer",fontSize:11,color:C.grey,letterSpacing:"0.08em",textTransform:"uppercase",fontFamily:"DM Sans,sans-serif"}}>Clear all</button>
          <Btn onClick={saveAll}>Upload All {items.length} →</Btn>
        </div>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"72px 1fr 140px 160px 80px 100px 110px 100px 40px",padding:"6px 0",marginBottom:2,borderBottom:`1px solid ${C.border}`}}>
        {["","Title / Artist","Artist","Medium","Year","Avail.","NGN Price","",""].map((h,i)=><div key={i} style={{padding:"0 10px",fontSize:9,letterSpacing:"0.15em",textTransform:"uppercase",color:C.lightGrey}}>{h}</div>)}
      </div>
      <div style={{display:"flex",flexDirection:"column",gap:2}}>
        {items.map((it,idx)=><BatchCard key={it.id} item={it} index={idx} onUpdate={update} onRemove={remove} artists={artists}/>)}
      </div>
      <div style={{marginTop:20,paddingTop:20,borderTop:`1px solid ${C.border}`,display:"flex",justifyContent:"flex-end"}}>
        <Btn onClick={saveAll}>Upload All {items.length} →</Btn>
      </div>
    </>)}
  </div>);
}

function BatchCard({item,onUpdate,onRemove,artists}){
  const [exp,setExp]=useState(false);
  const u=f=>e=>onUpdate(item.id,f,typeof e==="string"?e:e.target.value);
  const artistUnmatched=item.parsedArtist&&!item.resolvedArtistId;
  return(<div style={{border:`1px solid ${artistUnmatched?"#ffcccc":C.border}`,background:C.white}}>
    <div style={{display:"grid",gridTemplateColumns:"72px 1fr 140px 160px 80px 100px 110px 100px 40px",alignItems:"center"}}>
      <img src={item.image} alt="" style={{width:72,height:72,objectFit:"cover",display:"block",borderRight:`1px solid ${C.border}`}}/>
      <div style={{padding:"0 12px"}}>
        <input value={item.title} onChange={u("title")} style={{width:"100%",border:"none",borderBottom:`1px solid ${C.border}`,padding:"4px 0",fontFamily:"Cormorant Garamond,serif",fontSize:16,outline:"none",background:"transparent",color:C.black}}/>
        {item.resolvedArtistName?<div style={{fontSize:10,color:"#1a7a3c",marginTop:3}}>✓ {item.resolvedArtistName}</div>:item.parsedArtist?<div style={{fontSize:10,color:"#cc3333",marginTop:3}}>⚠ No match: "{item.parsedArtist}"</div>:<div style={{fontSize:10,color:C.lightGrey,marginTop:3}}>{item.compressInfo}</div>}
      </div>
      <div style={{padding:"0 10px",borderLeft:`1px solid ${C.border}`}}>
        <select value={item.resolvedArtistId||""} onChange={e=>onUpdate(item.id,"resolvedArtistId",e.target.value)} style={{width:"100%",border:"none",padding:"4px 0",fontFamily:"DM Sans,sans-serif",fontSize:11,outline:"none",background:"transparent",color:artistUnmatched?C.orange:C.charcoal,appearance:"none"}}>
          <option value="">— artist —</option>
          {artists.map(a=><option key={a.id} value={a.id}>{a.name}</option>)}
        </select>
      </div>
      <div style={{padding:"0 10px",borderLeft:`1px solid ${C.border}`}}><input value={item.medium} onChange={u("medium")} placeholder="Medium" style={{width:"100%",border:"none",padding:"4px 0",fontFamily:"DM Sans,sans-serif",fontSize:11,outline:"none",background:"transparent",color:C.charcoal}}/></div>
      <div style={{padding:"0 10px",borderLeft:`1px solid ${C.border}`}}><input value={item.year} onChange={u("year")} placeholder="Year" style={{width:"100%",border:"none",padding:"4px 0",fontFamily:"DM Sans,sans-serif",fontSize:11,outline:"none",background:"transparent",color:C.charcoal}}/></div>
      <div style={{padding:"0 10px",borderLeft:`1px solid ${C.border}`}}><select value={item.availability} onChange={u("availability")} style={{width:"100%",border:"none",padding:"4px 0",fontFamily:"DM Sans,sans-serif",fontSize:11,outline:"none",background:"transparent",color:C.charcoal,appearance:"none"}}>{["Available","Sold","On Loan","NFS"].map(o=><option key={o}>{o}</option>)}</select></div>
      <div style={{padding:"0 10px",borderLeft:`1px solid ${C.border}`}}><input value={item.price||""} onChange={u("price")} placeholder="e.g. 4,500,000" style={{width:"100%",border:"none",padding:"4px 0",fontFamily:"DM Sans,sans-serif",fontSize:11,outline:"none",background:"transparent",color:C.charcoal}}/></div>
      <div style={{padding:"0 8px",borderLeft:`1px solid ${C.border}`,display:"flex",alignItems:"center",gap:6}}>
        <button onClick={()=>setExp(e=>!e)} style={{background:"none",border:"none",cursor:"pointer",fontSize:10,color:C.orange,fontFamily:"DM Sans,sans-serif"}}>{exp?"▲":"▼"}</button>
        <button onClick={()=>onRemove(item.id)} style={{background:"none",border:"none",cursor:"pointer",fontSize:18,color:C.lightGrey,lineHeight:1}}>×</button>
      </div>
    </div>
    {exp&&<div style={{padding:"16px 20px",borderTop:`1px solid ${C.border}`,background:"#fcfcfa",display:"grid",gridTemplateColumns:"1fr 1fr",gap:16}}>
      <div>
        <FInput label="Dimensions" value={item.dimensions} onChange={u("dimensions")} placeholder="e.g. 24x36"/>
        <FInput label="NGN Price" value={item.price||""} onChange={u("price")} placeholder="e.g. 4,500,000"/>
        <FTextarea label="Art Write-up" value={item.writeup} onChange={u("writeup")} placeholder="Description or note…"/>
      </div>
      <div>
        <PositionToggle value={item.image_position||"center"} onChange={v=>onUpdate(item.id,"image_position",v)}/>
        <TagInput tags={item.tags||[]} onChange={tags=>onUpdate(item.id,"tags",tags)}/>
      </div>
    </div>}
  </div>);
}


// ── Tag Input ─────────────────────────────
const SIZE_TAGS=[{value:"sm",label:"Small"},{value:"md",label:"Medium"},{value:"lg",label:"Large"},{value:"xl",label:"Extra Large"}];


// ── Image Position Toggle ─────────────────
function PositionToggle({value,onChange}){
  const opts=[{v:"center",label:"Centre"},{v:"top",label:"Top"}];
  return(
    <div style={{marginBottom:20}}>
      <label style={{fontSize:10,letterSpacing:"0.18em",textTransform:"uppercase",color:C.grey,display:"block",marginBottom:8}}>Thumbnail Position</label>
      <div style={{display:"flex",gap:0}}>
        {opts.map(o=>(
          <button key={o.v} onClick={()=>onChange(o.v)}
            style={{flex:1,padding:"8px 0",fontSize:10,letterSpacing:"0.1em",textTransform:"uppercase",fontFamily:"DM Sans,sans-serif",cursor:"pointer",
              border:`1px solid ${value===o.v?C.orange:C.border}`,
              background:value===o.v?"#fff8f5":C.white,
              color:value===o.v?C.orange:C.grey,
              marginRight:o.v==="center"?-1:0,
              transition:"all 0.15s"}}>
            {o.label}
          </button>
        ))}
      </div>
      <div style={{fontSize:10,color:C.lightGrey,marginTop:6}}>Controls vertical crop position in thumbnail grid</div>
    </div>
  );
}

function TagInput({tags,onChange}){
  const [input,setInput]=useState("");
  const current=tags||[];
  const add=val=>{
    const v=val.trim().toLowerCase().replace(/\s+/g,"-");
    if(v&&!current.includes(v)) onChange([...current,v]);
    setInput("");
  };
  const remove=v=>onChange(current.filter(t=>t!==v));
  const handleKey=e=>{ if(e.key==="Enter"||e.key===","){ e.preventDefault(); add(input); }};
  return(
    <div style={{marginBottom:20}}>
      <label style={{fontSize:10,letterSpacing:"0.18em",textTransform:"uppercase",color:C.grey,display:"block",marginBottom:8}}>Tags</label>
      {/* Size presets */}
      <div style={{display:"flex",gap:6,marginBottom:10,flexWrap:"wrap"}}>
        {SIZE_TAGS.map(s=>(
          <button key={s.value} onClick={()=>current.includes(s.value)?remove(s.value):add(s.value)}
            style={{padding:"4px 10px",fontSize:10,letterSpacing:"0.1em",textTransform:"uppercase",fontFamily:"DM Sans,sans-serif",cursor:"pointer",border:`1px solid ${current.includes(s.value)?C.orange:C.border}`,background:current.includes(s.value)?"#fff8f5":C.white,color:current.includes(s.value)?C.orange:C.grey,transition:"all 0.15s"}}>
            {s.label}
          </button>
        ))}
      </div>
      {/* Current tags */}
      <div style={{display:"flex",flexWrap:"wrap",gap:6,marginBottom:8}}>
        {current.map(t=>(
          <span key={t} style={{display:"inline-flex",alignItems:"center",gap:4,padding:"3px 10px",fontSize:10,letterSpacing:"0.08em",textTransform:"uppercase",background:C.bg,border:`1px solid ${C.border}`,color:C.charcoal}}>
            {t}
            <button onClick={()=>remove(t)} style={{background:"none",border:"none",cursor:"pointer",color:C.lightGrey,fontSize:12,lineHeight:1,padding:0}}>×</button>
          </span>
        ))}
      </div>
      {/* Free text input */}
      <div style={{display:"flex",gap:8}}>
        <input value={input} onChange={e=>setInput(e.target.value)} onKeyDown={handleKey}
          placeholder="Type a tag and press Enter (e.g. portrait, abstract, blue)"
          style={{flex:1,padding:"8px 12px",border:`1px solid ${C.border}`,fontFamily:"DM Sans,sans-serif",fontSize:12,outline:"none",color:C.black}}/>
        <button onClick={()=>add(input)}
          style={{padding:"8px 14px",background:C.black,color:C.white,border:"none",cursor:"pointer",fontSize:10,letterSpacing:"0.1em",textTransform:"uppercase",fontFamily:"DM Sans,sans-serif"}}>Add</button>
      </div>
      <div style={{fontSize:10,color:C.lightGrey,marginTop:6,letterSpacing:"0.06em"}}>Size presets: sm · md · lg · xl — plus any free tag: subject, style, colour, series</div>
    </div>
  );
}

function AddArtistForm({reload}){
  const [form,setForm]=useState({name:"",nationality:"",medium:"",bio:"",link:""});
  const [ok,setOk]=useState(false);const [err,setErr]=useState("");const [saving,setSaving]=useState(false);
  const f=k=>e=>setForm(p=>({...p,[k]:e.target.value}));
  const handlePortrait=async e=>{const file=e.target.files[0];if(!file)return;const {dataUrl}=await compressImage(file);setForm(p=>({...p,_portraitData:dataUrl}));};
  const save=async()=>{
    if(!form.name.trim()){setErr("Artist name required.");return;}
    setSaving(true);setErr("");
    try{
      let portrait_url="";
      if(form._portraitData)portrait_url=await sbUploadImage("artist-portraits",form._portraitData);
      const {_portraitData,...rest}=form;
      await sbInsert("artists",{...rest,portrait_url,name:form.name.trim()});
      await reload();
      setForm({name:"",nationality:"",medium:"",bio:"",link:""});
      setOk(true);setTimeout(()=>setOk(false),3000);
    }catch(e){setErr("Error: "+e.message);}
    setSaving(false);
  };
  return(<div style={{maxWidth:800}}>
    <SuccessMsg show={ok} text="Artist saved."/>
    <ErrMsg text={err}/>
    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:24}}>
      <div>
        <FInput label="Full Name *" value={form.name} onChange={f("name")} placeholder="e.g. Amara Osei"/>
        <FInput label="Nationality / Origin" value={form.nationality} onChange={f("nationality")} placeholder="e.g. Ghanaian, b. 1980"/>
        <FInput label="Primary Medium" value={form.medium} onChange={f("medium")} placeholder="e.g. Oil on canvas"/>
        <FTextarea label="Short Biography" value={form.bio} onChange={f("bio")} placeholder="2–4 sentences…"/>
        <FInput label="Website / Instagram" value={form.link} onChange={f("link")} placeholder="https://…"/>
      </div>
      <div>
        <div style={{marginBottom:20}}>
          <label style={{fontSize:10,letterSpacing:"0.18em",textTransform:"uppercase",color:C.grey,display:"block",marginBottom:8}}>Portrait (optional)</label>
          <div style={{border:`1.5px dashed ${C.border}`,padding:28,textAlign:"center",position:"relative",cursor:"pointer"}}>
            <input type="file" accept="image/*" onChange={handlePortrait} style={{position:"absolute",inset:0,opacity:0,cursor:"pointer",width:"100%",height:"100%"}}/>
            {form._portraitData?<img src={form._portraitData} alt="" style={{maxWidth:"100%",maxHeight:160,objectFit:"contain"}}/>:<div style={{fontSize:12,color:C.grey}}>Upload portrait<br/><span style={{fontSize:10,color:C.lightGrey}}>Auto-compressed</span></div>}
          </div>
        </div>
      </div>
    </div>
    <Btn onClick={save}>{saving?"Saving…":"Save Artist"}</Btn>
  </div>);
}

function AddArtworkForm({artists,reload}){
  const [form,setForm]=useState({title:"",year:"",medium:"",dimensions:"",series:"",availability:"Available",writeup:"",_imageData:"",artist_id:"",price:"",tags:[],image_position:"center"});
  const [ok,setOk]=useState(false);const [err,setErr]=useState("");const [saving,setSaving]=useState(false);
  const f=k=>e=>setForm(p=>({...p,[k]:e.target.value}));
  const handleImage=async e=>{const file=e.target.files[0];if(!file)return;const name=file.name.replace(/\.[^.]+$/,"").replace(/[-_]/g," ").replace(/\b\w/g,c=>c.toUpperCase());const {dataUrl,origW,origH}=await compressImage(file);setForm(p=>({...p,_imageData:dataUrl,title:p.title||name,dimensions:p.dimensions||`${origW} × ${origH} px`}));};
  const save=async()=>{
    if(!form.title.trim()){setErr("Title required.");return;}
    if(!form.artist_id){setErr("Select an artist.");return;}
    if(!form._imageData){setErr("Please upload an image.");return;}
    setSaving(true);setErr("");
    try{
      const image_url=await sbUploadImage("artwork-images",form._imageData);
      // Build insert object with only core fields first
      const insertData={
        artist_id:form.artist_id,
        title:form.title.trim(),
        year:form.year||null,
        medium:form.medium||null,
        dimensions:form.dimensions||null,
        series:form.series||null,
        availability:form.availability||"Available",
        writeup:form.writeup||null,
        image_url,
      };
      // Add optional columns only if they exist in schema
      if(form.price) insertData.price=form.price;
      if(form.tags&&form.tags.length>0) insertData.tags=form.tags;
      if(form.image_position) insertData.image_position=form.image_position;
      await sbInsert("artworks",insertData);
      await reload();
      setForm({title:"",year:"",medium:"",dimensions:"",series:"",availability:"Available",writeup:"",_imageData:"",artist_id:"",price:"",tags:[],image_position:"center"});
      setOk(true);setTimeout(()=>setOk(false),3000);
    }catch(e){setErr("Error: "+e.message);}
    setSaving(false);
  };
  return(<div style={{maxWidth:800}}>
    <SuccessMsg show={ok} text="Artwork saved."/>
    <ErrMsg text={err}/>
    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:24}}>
      <div>
        <div style={{marginBottom:20}}>
          <label style={{fontSize:10,letterSpacing:"0.18em",textTransform:"uppercase",color:C.grey,display:"block",marginBottom:8}}>Image *</label>
          <div style={{border:`1.5px dashed ${C.border}`,padding:28,textAlign:"center",position:"relative",cursor:"pointer"}}>
            <input type="file" accept="image/*" onChange={handleImage} style={{position:"absolute",inset:0,opacity:0,cursor:"pointer",width:"100%",height:"100%"}}/>
            {form._imageData?<img src={form._imageData} alt="" style={{maxWidth:"100%",maxHeight:180,objectFit:"contain"}}/>:<div style={{fontSize:12,color:C.grey}}>Upload image<br/><span style={{fontSize:10,color:C.lightGrey}}>Auto-compressed</span></div>}
          </div>
        </div>
        <FInput label="Title *" value={form.title} onChange={f("title")} placeholder="Artwork title"/>
        <FInput label="Year" value={form.year} onChange={f("year")} placeholder="e.g. 2024"/>
        <FInput label="Medium" value={form.medium} onChange={f("medium")} placeholder="e.g. Oil on linen"/>
      </div>
      <div>
        <FSelect label="Artist *" value={form.artist_id} onChange={f("artist_id")} options={[{value:"",label:"— Select artist —"},...artists.map(a=>({value:a.id,label:a.name}))]}/>
        <FInput label="Dimensions" value={form.dimensions} onChange={f("dimensions")} placeholder="e.g. 24x36"/>
        <FInput label="Edition / Series" value={form.series} onChange={f("series")} placeholder="e.g. Edition 1/5"/>
        <FSelect label="Availability" value={form.availability} onChange={f("availability")} options={["Available","Sold","On Loan","NFS"]}/>
        <FInput label="NGN Price" value={form.price} onChange={f("price")} placeholder="e.g. 4,500,000"/>
        <FTextarea label="Write-up" value={form.writeup} onChange={f("writeup")} placeholder="Description or note…"/>
      </div>
    </div>
    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:24}}>
      <PositionToggle value={form.image_position} onChange={v=>setForm(p=>({...p,image_position:v}))}/>
      <TagInput tags={form.tags} onChange={tags=>setForm(p=>({...p,tags}))}/>
    </div>
    <ErrMsg text={err}/>
    <SuccessMsg show={ok} text="Artwork saved."/>
    <div style={{marginTop:16}}>
      <button type="button"
        onClick={()=>{ save(); }}
        disabled={saving}
        style={{background:saving?"#888":C.black,color:C.white,border:"none",cursor:saving?"not-allowed":"pointer",padding:"13px 32px",fontSize:11,letterSpacing:"0.15em",textTransform:"uppercase",fontFamily:"DM Sans,sans-serif"}}>
        {saving?"Uploading…":"Save Artwork"}
      </button>
    </div>
  </div>);
}
